base.script:
const OriginalWorker = window.Worker;
window.Worker = function(scriptURL) {
    if (scriptURL.includes('jsdelivr.net') || scriptURL.includes('js/workers/') || scriptURL.includes('worker')) {
        let fullURL = scriptURL;
        if (!fullURL.startsWith('http')) {
            fullURL = "https://cdn.jsdelivr.net/gh/jsonsonson/baals@main/" + fullURL.replace(/^\//, '');
        }
        if (fullURL.endsWith('.png')) {
            fullURL = fullURL.replace('.png', '.webp');
        }
        const blobCode = "importScripts('" + fullURL + "');";
        const blob = new Blob([blobCode], { type: 'application/javascript' });
        const blobURL = URL.createObjectURL(blob);
        return new OriginalWorker(blobURL);
    }
    return new OriginalWorker(scriptURL);
};

