function iniciarJogo(idioma) {
  console.log("Iniciando jogo para a rota:", idioma);

  const URL_BASE_JOGO = "https://cdn.jsdelivr.net/gh/jsonsonson/baals@main/";
  const originalFetch = window.fetch;

  window.fetch = async function(...args) {
    let url = args[0];

    if (typeof url === 'string') {
      url = decodeURIComponent(url);

      if (url.includes("content:/media/external/file/")) {
         url = url.split("content:/media/external/file/")[1];
      }

      if (url.includes('?')) {
        url = url.split('?')[0];
      }

      if (url.startsWith('http://192.168') || (!url.startsWith('http://') && !url.startsWith('https://'))) {
        const limpaLocal = url.replace(/^http:\/\/192\.168\.[0-9.]+(:[0-9]+)?\//, '');
        url = URL_BASE_JOGO + limpaLocal.replace(/^\//, '');
      }

      // 🔥 INTERCEPTADOR INTELIGENTE DE TEXTURAS:
      // Se o arquivo solicitado terminar com as extensões problemáticas do console antigo
      if (url.endsWith('.png')) {
          // Verifica se a engine está caçando uma textura que você tem como .png ou se realmente migrou para .webp
          // Mantemos a conversão padrão para .webp, mas ignoramos se o arquivo requisitado for estrutural (.json, etc)
          url = url.replace('.png', '.webp');
      }

      if (url.includes('lang-en.json') && idioma === 'pt') {
        url = url.replace('lang-en.json', 'lang-pt-br.json');
      }

      args[0] = url;
    }
    return originalFetch.apply(this, args);
  };

  const liberarAudio = () => {
      if (typeof AudioContext !== 'undefined' || typeof webkitAudioContext !== 'undefined') {
          if (window.audioContext && window.audioContext.state === 'suspended') {
              window.audioContext.resume();
          }
      }
      window.removeEventListener('click', liberarAudio);
      window.removeEventListener('touchstart', liberarAudio);
  };
  window.addEventListener('click', liberarAudio);
  window.addEventListener('touchstart', liberarAudio);

  document.getElementById('message').style.display = 'block';

  const scriptLoading = document.createElement('script');
  scriptLoading.src = URL_BASE_JOGO + "js/loading.js";
  document.body.appendChild(scriptLoading);

  const scriptBoot = document.createElement('script');
  scriptBoot.src = URL_BASE_JOGO + "js/boot.js";
  document.body.appendChild(scriptBoot);
}

const listaIdiomas = navigator.languages && navigator.languages.length > 0 ? navigator.languages : [navigator.language || ''];
const idiomaPrincipal = listaIdiomas[0].toLowerCase();

if (idiomaPrincipal.startsWith('pt')) {
  iniciarJogo('pt');
} else {
  iniciarJogo('en');
}
